def merge_dict_defaults(data, defaults):
    if not isinstance(defaults, dict):
        return data
    merged = {}
    source = data if isinstance(data, dict) else {}
    for key, default_value in defaults.items():
        current_value = source.get(key)
        if isinstance(default_value, dict):
            merged[key] = merge_dict_defaults(current_value, default_value)
        else:
            merged[key] = current_value if current_value is not None else default_value
    for key, value in source.items():
        if key not in merged:
            merged[key] = value
    return merged


def normalize_commercial_era(value):
    text = re.sub(r"[^0-9a-z]+", "", str(value or "").lower())
    if not text:
        return ""
    mapping = {
        "80s": "80s",
        "1980s": "80s",
        "90s": "90s",
        "1990s": "90s",
        "00s": "2000s",
        "2000s": "2000s",
        "2010s": "2010s",
        "70s": "70s",
        "1970s": "70s",
    }
    return mapping.get(text, str(value or "").strip())


def normalize_commercial_category(value):
    text = re.sub(r"[^a-z0-9]+", "-", str(value or "").strip().lower()).strip("-")
    return text


def display_commercial_category(value):
    normalized = normalize_commercial_category(value)
    if not normalized:
        return ""
    if normalized in COMMERCIAL_SPECIAL_CATEGORY_LABELS:
        return COMMERCIAL_SPECIAL_CATEGORY_LABELS[normalized]
    return " ".join(part.capitalize() for part in normalized.split("-"))


def commercials_config_signature(config):
    return stable_hash(json.dumps(config or {}, sort_keys=True))


def normalize_commercial_mode(value, enabled=True):
    text = str(value or "").strip().lower().replace("-", "_")
    aliases = {
        "none": "off",
        "disabled": "off",
        "commercials_off": "off",
        "no_commercials": "off",
        "between": "between_episodes",
        "between_episodes_only": "between_episodes",
        "between_shows": "between_episodes",
        "natural_breaks": "timed_midroll",
        "timed_breaks": "timed_midroll",
        "timed_break": "timed_midroll",
        "midroll": "timed_midroll",
        "hybrid": "timed_midroll",
    }
    mode = aliases.get(text, text)
    if mode not in COMMERCIAL_MODES:
        mode = "between_episodes"
    if not enabled:
        return "off"
    return mode


def commercial_mode_label(value):
    return COMMERCIAL_MODE_LABELS.get(normalize_commercial_mode(value), COMMERCIAL_MODE_LABELS["between_episodes"])


def sanitize_catalog_category(value):
    text = re.sub(r"\s+", " ", str(value or "").strip())
    return text[:64]


def catalog_category_key(value):
    return normalize_title(sanitize_catalog_category(value))


def catalog_channel_settings_defaults():
    return {
        "enabled": True,
        "channel_number": 0,
        "display_name": "",
        "vault_category_mode": "channel_name",
        "vault_category": "",
        "custom_vault_category": "",
        "description": "",          # user-written blurb shown in Vault
        "vault_genre_tags": "",     # comma-separated extra genre tags for Vault filters
    }


def normalize_catalog_channel_settings(settings):
    source = settings if isinstance(settings, dict) else {}
    normalized = {}
    for channel_id, value in source.items():
        if not isinstance(channel_id, str) or not isinstance(value, dict):
            continue
        merged = merge_dict_defaults(value, catalog_channel_settings_defaults())
        mode = str(merged.get("vault_category_mode", "channel_name") or "channel_name").lower()
        if mode not in {"channel_name", "builtin", "custom"}:
            mode = "channel_name"
        try:
            number = int(merged.get("channel_number", 0) or 0)
        except (TypeError, ValueError):
            number = 0
        normalized[channel_id] = {
            "enabled": bool(merged.get("enabled", True)),
            "channel_number": max(0, min(9999, number)),
            "display_name": str(merged.get("display_name", "") or "").strip(),
            "vault_category_mode": mode,
            "vault_category": sanitize_catalog_category(merged.get("vault_category", "")),
            "custom_vault_category": sanitize_catalog_category(merged.get("custom_vault_category", "")),
            "description": str(merged.get("description", "") or "").strip(),
            "vault_genre_tags": str(merged.get("vault_genre_tags", "") or "").strip(),
        }
    return normalized


def catalog_channel_id_from_info(info):
    if not isinstance(info, dict):
        return ""
    channel_type = str(info.get("channel_type", "media") or "media")
    if channel_type == "weatherstar":
        return "special:weatherstar"
    if channel_type == "radiowave":
        return "special:radiowave"
    if channel_type == "youtube":
        return "special:youtube"
    root_path = os.path.realpath(info.get("root_path", "") or "")
    if root_path:
        return f"media:{root_path}"
    return f"media-name:{normalize_title(info.get('name', 'channel'))}"


CHANNEL_BUG_SUPPORTED_EXTS = (".png", ".jpg", ".jpeg", ".webp", ".bmp", ".gif")
CHANNEL_BUG_PREFERRED_NAMES = ("logo.png", "channel.png", "bug.png")
CHANNEL_BUG_CORNER_OPTIONS = ("top-left", "top-right", "bottom-left", "bottom-right")

# Valid per-channel override modes
CHANNEL_BUG_OVERRIDE_MODES = ("global", "custom", "off")

# Timing defaults
_TIMING_DEFAULTS = {
    "always_visible": False,
    "on_channel_tune": True,
    "on_program_start": False,
    "periodic": False,
    "duration_seconds": 5,
    "periodic_interval_minutes": 10,
}

# Friendly "Show for" options: (label, value_seconds)
CHANNEL_BUG_DURATION_OPTIONS = [
    ("5 seconds", 5),
    ("10 seconds", 10),
    ("15 seconds", 15),
    ("30 seconds", 30),
    ("1 minute", 60),
]

# Friendly "Repeat every" options: (label, value_minutes)
CHANNEL_BUG_INTERVAL_OPTIONS = [
    ("1 minute", 1),
    ("5 minutes", 5),
    ("10 minutes", 10),
    ("15 minutes", 15),
    ("30 minutes", 30),
]


def _normalize_timing(t):
    """Return a fully validated timing sub-dict."""
    if not isinstance(t, dict):
        t = {}
    result = dict(_TIMING_DEFAULTS)
    for key in ("always_visible", "on_channel_tune", "on_program_start", "periodic"):
        if key in t:
            result[key] = bool(t[key])
    if "duration_seconds" in t:
        result["duration_seconds"] = max(1, min(3600, int(t["duration_seconds"] or 5)))
    if "periodic_interval_minutes" in t:
        result["periodic_interval_minutes"] = max(1, min(120, int(t["periodic_interval_minutes"] or 10)))
    # always_visible is mutually exclusive with other triggers
    if result["always_visible"]:
        result["on_channel_tune"] = False
        result["on_program_start"] = False
        result["periodic"] = False
    elif result["on_program_start"]:
        # on_program_start is mutually exclusive with on_channel_tune —
        # the logo fires on automatic show changes only, not on user channel switches.
        result["on_channel_tune"] = False
    elif not any([result["on_channel_tune"], result["on_program_start"], result["periodic"]]):
        # Require at least one trigger; default to on_channel_tune
        result["on_channel_tune"] = True
    return result


def _migrate_old_timing_fields(settings_dict, fallback_timing=None):
    """Build a timing sub-dict from old flat timing_mode fields (migration)."""
    existing = settings_dict.get("timing")
    if isinstance(existing, dict):
        return _normalize_timing(existing)

    old_mode = settings_dict.get("timing_mode", "")
    old_dur = settings_dict.get("timing_duration") or settings_dict.get("duration_seconds") or 5
    old_interval = settings_dict.get("periodic_interval") or settings_dict.get("periodic_interval_minutes") or 10

    try:
        old_dur = int(old_dur)
    except (TypeError, ValueError):
        old_dur = 5
    try:
        old_interval = int(old_interval)
    except (TypeError, ValueError):
        old_interval = 10

    t = {"duration_seconds": old_dur, "periodic_interval_minutes": old_interval}
    if old_mode in ("always", "always_visible"):
        t["always_visible"] = True
    elif old_mode in ("on_tune", "channel_tune"):
        t["on_channel_tune"] = True
    elif old_mode == "on_program_start":
        t["on_program_start"] = True
    elif old_mode == "periodic":
        t["on_channel_tune"] = True
        t["periodic"] = True
    else:
        # No old mode or unknown — use fallback or default (always visible)
        if isinstance(fallback_timing, dict):
            return dict(fallback_timing)
        t["always_visible"] = True
    return _normalize_timing(t)


def channel_bug_settings_defaults():
    return {
        "enabled": False,
        "corner": "bottom-right",
        "opacity": 0.75,
        "size": 80,
        "margin": 18,
        "grayscale_on_video": False,
        "fade": True,
        "timing": dict(_TIMING_DEFAULTS),
        "channel_overrides": {},
    }


def channel_bug_channel_defaults():
    return {
        "mode": "global",
    }


def _normalize_channel_bug_override(override, global_settings):
    """Normalize a single per-channel override dict against global defaults."""
    if not isinstance(override, dict):
        return {"mode": "global"}
    mode = str(override.get("mode", "global") or "global")
    # Migrate legacy "enabled" bool-only format
    if mode not in CHANNEL_BUG_OVERRIDE_MODES:
        if "enabled" in override and not override.get("enabled", True):
            mode = "off"
        else:
            mode = "global"
    result = {"mode": mode}
    if mode == "custom":
        gs = global_settings or {}
        result["corner"] = str(override.get("corner") or gs.get("corner", "bottom-right"))
        if result["corner"] not in CHANNEL_BUG_CORNER_OPTIONS:
            result["corner"] = gs.get("corner", "bottom-right")
        result["opacity"] = max(0.1, min(1.0, float(override.get("opacity") or gs.get("opacity", 0.75))))
        result["size"] = max(32, min(256, int(override.get("size") or gs.get("size", 80))))
        result["margin"] = max(0, min(120, int(override.get("margin") if override.get("margin") is not None else gs.get("margin", 18))))
        result["grayscale_on_video"] = bool(override.get("grayscale_on_video") if "grayscale_on_video" in override else gs.get("grayscale_on_video", False))
        result["fade"] = bool(override.get("fade") if override.get("fade") is not None else gs.get("fade", True))
        # Timing: migrate and normalize
        global_timing = gs.get("timing") or {}
        result["timing"] = _migrate_old_timing_fields(override, fallback_timing=global_timing)
    return result


def normalize_channel_bug_settings(settings):
    defaults = channel_bug_settings_defaults()
    source = settings if isinstance(settings, dict) else {}
    merged = dict(defaults)
    for k in ("enabled", "corner", "opacity", "size", "margin", "grayscale_on_video", "fade"):
        if k in source:
            merged[k] = source[k]
    merged["enabled"] = bool(merged.get("enabled", False))
    merged["corner"] = str(merged.get("corner", "bottom-right"))
    if merged["corner"] not in CHANNEL_BUG_CORNER_OPTIONS:
        merged["corner"] = "bottom-right"
    merged["opacity"] = max(0.1, min(1.0, float(merged.get("opacity", 0.75) or 0.75)))
    merged["size"] = max(32, min(256, int(merged.get("size", 80) or 80)))
    merged["margin"] = max(0, min(120, int(merged.get("margin", 18) or 18)))
    merged["grayscale_on_video"] = bool(merged.get("grayscale_on_video", False))
    merged["fade"] = bool(merged.get("fade", True))
    # Timing: migrate flat fields or normalize existing sub-dict
    merged["timing"] = _migrate_old_timing_fields(source)
    overrides_raw = source.get("channel_overrides") or {}
    normalized_overrides = {}
    for ch_name, override in overrides_raw.items():
        if not isinstance(ch_name, str) or not isinstance(override, dict):
            continue
        normalized_overrides[str(ch_name)] = _normalize_channel_bug_override(override, merged)
    merged["channel_overrides"] = normalized_overrides
    return merged


def get_effective_channel_logo_settings(channel_name, global_settings):
    """Return the resolved effective logo settings for a given channel.

    Priority:
    1. Global master toggle: if disabled, return enabled=False.
    2. Channel override mode='off': return enabled=False.
    3. Channel override mode='custom': use channel's custom settings (timing, grayscale, etc.).
    4. Channel override mode='global' or no override: use global settings.
    """
    gs = global_settings if isinstance(global_settings, dict) else channel_bug_settings_defaults()
    if not gs.get("enabled", False):
        result = dict(gs)
        result["enabled"] = False
        return result
    overrides = gs.get("channel_overrides") or {}
    ch_override = overrides.get(channel_name) if channel_name else None
    if not isinstance(ch_override, dict):
        return dict(gs)
    mode = ch_override.get("mode", "global")
    if mode == "off":
        result = dict(gs)
        result["enabled"] = False
        return result
    if mode == "custom":
        result = dict(gs)
        result["corner"] = ch_override.get("corner", gs.get("corner", "bottom-right"))
        result["opacity"] = ch_override.get("opacity", gs.get("opacity", 0.75))
        result["size"] = ch_override.get("size", gs.get("size", 80))
        result["margin"] = ch_override.get("margin", gs.get("margin", 18))
        result["grayscale_on_video"] = ch_override.get("grayscale_on_video", gs.get("grayscale_on_video", False))
        result["fade"] = ch_override.get("fade", gs.get("fade", True))
        result["timing"] = _normalize_timing(ch_override.get("timing") or gs.get("timing") or {})
        return result
    # mode == "global" or unknown: use global settings unchanged
    return dict(gs)


def find_channel_bug_logo(root_path, channel_name):
    """Discover the best logo image in <root_path>/Logos/.

    Returns an absolute path string or "" if none found.
    """
    if not root_path:
        return ""
    logos_dir = os.path.join(root_path, "Logos")
    if not os.path.isdir(logos_dir):
        return ""
    try:
        entries = os.listdir(logos_dir)
    except OSError:
        return ""
    lower_entries = {e.lower(): e for e in entries}

    def candidate(name):
        actual = lower_entries.get(name.lower())
        if actual:
            p = os.path.join(logos_dir, actual)
            if os.path.isfile(p):
                return p
        return ""

    # Exact preferred names
    for name in CHANNEL_BUG_PREFERRED_NAMES:
        c = candidate(name)
        if c:
            return c

    # <channel_name>.png variants
    safe_name = re.sub(r"[^\w\-. ]", "", channel_name or "").strip()
    for ext in CHANNEL_BUG_SUPPORTED_EXTS:
        c = candidate(f"{safe_name}{ext}")
        if c:
            return c

    # Any supported image in Logos/, prefer PNG first
    png_hits = []
    other_hits = []
    for entry in sorted(entries):
        ext = os.path.splitext(entry)[1].lower()
        if ext in CHANNEL_BUG_SUPPORTED_EXTS:
            full = os.path.join(logos_dir, entry)
            if os.path.isfile(full):
                if ext == ".png":
                    png_hits.append(full)
                else:
                    other_hits.append(full)
    if png_hits:
        return png_hits[0]
    if other_hits:
        return other_hits[0]
    return ""


def load_channel_bug_pixmap(root_path, channel_name, size):
    """Return a cached, pre-scaled QPixmap for the channel bug logo.

    Loads from disk only when the cache is cold or invalidated.
    Returns None if no logo exists (caller should use fallback).
    """
    cache_key = (root_path, channel_name, size)
    if cache_key in _CHANNEL_BUG_CACHE:
        return _CHANNEL_BUG_CACHE[cache_key]
    path = find_channel_bug_logo(root_path, channel_name)
    if not path:
        _CHANNEL_BUG_CACHE[cache_key] = None
        return None
    try:
        pixmap = QPixmap(path)
        if pixmap.isNull():
            _CHANNEL_BUG_CACHE[cache_key] = None
            return None
        pixmap = pixmap.scaled(size, size, Qt.KeepAspectRatio, Qt.SmoothTransformation)
        _CHANNEL_BUG_CACHE[cache_key] = pixmap
        return pixmap
    except Exception:
        _CHANNEL_BUG_CACHE[cache_key] = None
        return None


def render_channel_bug_fallback(channel_name, size, dark_bg=True):
    """Render a clean text-based fallback bug as a QPixmap."""
    name = (channel_name or "TV").strip()
    cleaned = re.findall(r"[A-Za-z0-9]+", name)
    if not cleaned:
        initials = "TV"
    elif len(cleaned) == 1:
        word = cleaned[0]
        initials = word[:6].upper() if len(word) <= 6 else word[:4].upper()
    else:
        initials = "".join(part[0] for part in cleaned[:4]).upper()

    pm = QPixmap(size, size)
    pm.fill(Qt.transparent)
    painter = QPainter(pm)
    painter.setRenderHint(QPainter.Antialiasing, True)
    painter.setRenderHint(QPainter.TextAntialiasing, True)

    bg = QColor(0, 0, 0, 170) if dark_bg else QColor(255, 255, 255, 160)
    border = QColor(200, 200, 200, 120) if dark_bg else QColor(80, 80, 80, 100)
    text_color = QColor(255, 255, 255, 230) if dark_bg else QColor(20, 20, 20, 220)

    r = size * 0.14
    painter.setBrush(bg)
    painter.setPen(QPen(border, max(1, size // 48)))
    painter.drawRoundedRect(QRect(2, 2, size - 4, size - 4), r, r)

    font_size = max(8, int(size * (0.38 if len(initials) <= 2 else 0.28 if len(initials) <= 4 else 0.22)))
    font = QFont(".AppleSystemUIFont", font_size, QFont.Bold)
    draw_text_with_stroke(
        painter,
        QRect(3, 3, size - 6, size - 6),
        initials,
        font,
        text_color,
        QColor(0, 0, 0, 235) if dark_bg else QColor(255, 255, 255, 225),
        max(1.0, size / 38.0),
        Qt.AlignCenter | Qt.TextSingleLine,
        shadow=True,
        clip_rect=QRect(2, 2, size - 4, size - 4),
        elide=True,
    )
    painter.end()
    return pm


def make_grayscale_pixmap(src_pixmap):
    """Return a grayscale copy of src_pixmap with original alpha preserved.

    Converts RGB to luminance; alpha channel is taken from the source unchanged.
    Result is cached by the caller (ChannelBugOverlay._grayscale_pixmap).
    """
    if src_pixmap is None or src_pixmap.isNull():
        return src_pixmap
    # Draw grayscale version onto an ARGB target, then mask with original alpha
    gray_img = src_pixmap.toImage().convertToFormat(QImage.Format_Grayscale8).convertToFormat(QImage.Format_ARGB32)
    gray_pm = QPixmap.fromImage(gray_img)
    result = QPixmap(src_pixmap.size())
    result.fill(Qt.transparent)
    p = QPainter(result)
    p.drawPixmap(0, 0, gray_pm)
    # DestinationIn multiplies destination alpha by source alpha, preserving
    # the grayscale RGB while restoring the original transparency mask.
    p.setCompositionMode(QPainter.CompositionMode_DestinationIn)
    p.drawPixmap(0, 0, src_pixmap)
    p.end()
    return result


def invalidate_channel_bug_cache(root_path=None, channel_name=None):
    """Flush channel bug cache entries. Pass both to flush one channel, or
    neither to flush everything."""
    if root_path is None and channel_name is None:
        _CHANNEL_BUG_CACHE.clear()
        return
    to_del = [k for k in _CHANNEL_BUG_CACHE if k[0] == root_path and k[1] == channel_name]
    for k in to_del:
        del _CHANNEL_BUG_CACHE[k]


def normalize_commercials_config(settings):
    defaults = commercial_settings_defaults()
    source = settings if isinstance(settings, dict) else {}
    merged = merge_dict_defaults(source, defaults)
    raw_enabled = merged.get("enabled", merged.get("commercials_enabled", False))
    if "commercials_enabled" in source:
        raw_enabled = source.get("commercials_enabled")
    mode = normalize_commercial_mode(merged.get("mode", defaults["mode"]), enabled=bool(raw_enabled))
    enabled = bool(raw_enabled) and mode != "off"
    merged["schema_version"] = COMMERCIALS_SCHEMA_VERSION
    merged["mode"] = mode
    merged["enabled"] = enabled
    merged["commercials_enabled"] = enabled
    merged["allow_fallback"] = bool(merged.get("allow_fallback", True))
    merged["allow_bumpers"] = bool(merged.get("allow_bumpers", True))
    merged["allow_promos"] = bool(merged.get("allow_promos", True))
    merged["allow_station_ids"] = bool(merged.get("allow_station_ids", True))
    merged["prefer_same_era"] = bool(merged.get("prefer_same_era", True))
    merged["root_folder"] = os.path.abspath(os.path.expanduser((merged.get("root_folder") or "").strip())) if merged.get("root_folder") else ""
    merged["simple_preset"] = normalize_commercial_simple_preset(merged.get("simple_preset", "classic_cable"))
    merged["preferred_era"] = normalize_commercial_era(merged.get("preferred_era", ""))
    merged["preferred_category"] = normalize_commercial_category(merged.get("preferred_category", ""))
    merged["density"] = str(merged.get("density", "light") or "light").lower()
    if merged["density"] not in {"light", "medium", "heavy", "custom"}:
        merged["density"] = "light"
    interval_value = merged.get("midroll_interval_minutes", merged.get("target_break_interval_minutes", defaults["midroll_interval_minutes"]))
    for key in ("min_ads_per_break", "max_ads_per_break"):
        try:
            merged[key] = int(merged.get(key, defaults[key]) or defaults[key])
        except (TypeError, ValueError):
            merged[key] = defaults[key]
    try:
        merged["midroll_interval_minutes"] = int(interval_value or defaults["midroll_interval_minutes"])
    except (TypeError, ValueError):
        merged["midroll_interval_minutes"] = defaults["midroll_interval_minutes"]
    merged["midroll_interval_minutes"] = max(6, min(60, merged["midroll_interval_minutes"]))
    merged["min_ads_per_break"] = max(0, merged["min_ads_per_break"])
    merged["max_ads_per_break"] = max(merged["min_ads_per_break"], merged["max_ads_per_break"])
    normalized_overrides = {}
    for channel_name, override in (merged.get("channel_overrides") or {}).items():
        if not isinstance(channel_name, str) or not isinstance(override, dict):
            continue
        override_enabled_mode = str(override.get("enabled_mode", "inherit") or "inherit")
        override_enabled = enabled if override_enabled_mode == "inherit" else override_enabled_mode == "on"
        override_mode = normalize_commercial_mode(override.get("mode", merged["mode"]), enabled=override_enabled)
        override_density = str(override.get("density", merged["density"]) or merged["density"]).lower()
        if override_density not in {"light", "medium", "heavy", "custom"}:
            override_density = merged["density"]
        normalized_overrides[str(channel_name)] = {
            "enabled_mode": override_enabled_mode if override_enabled_mode in {"inherit", "on", "off"} else "inherit",
            "preferred_era": normalize_commercial_era(override.get("preferred_era", "")),
            "preferred_category": normalize_commercial_category(override.get("preferred_category", "")),
            "mode": override_mode,
            "density": override_density,
            "min_ads_per_break": int(override.get("min_ads_per_break", merged["min_ads_per_break"]) or merged["min_ads_per_break"]),
            "max_ads_per_break": int(override.get("max_ads_per_break", merged["max_ads_per_break"]) or merged["max_ads_per_break"]),
            "midroll_interval_minutes": int(override.get("midroll_interval_minutes", override.get("target_break_interval_minutes", merged["midroll_interval_minutes"])) or merged["midroll_interval_minutes"]),
            "allow_fallback": bool(override.get("allow_fallback", merged["allow_fallback"])),
            "allow_bumpers": bool(override.get("allow_bumpers", merged["allow_bumpers"])),
            "allow_promos": bool(override.get("allow_promos", merged["allow_promos"])),
            "allow_station_ids": bool(override.get("allow_station_ids", merged["allow_station_ids"])),
            "prefer_same_era": bool(override.get("prefer_same_era", merged["prefer_same_era"])),
        }
    merged["channel_overrides"] = normalized_overrides
    for deprecated_key in (
        "smart_breaks",
        "skip_midroll_if_no_smart_breaks",
        "learned_breaks",
        "black_frame_breaks",
        "silence_breaks",
        "pre_roll_enabled",
        "post_roll_enabled",
        "prefer_promos",
        "min_seconds_between_breaks",
        "target_break_interval_minutes",
        "minimum_content_before_first_break_seconds",
        "break_jitter_seconds",
        "max_ad_seconds_per_half_hour",
    ):
        merged.pop(deprecated_key, None)
    return merged


def infer_commercial_asset_kind(parts):
    joined = " ".join(str(part or "").lower() for part in parts)
    if re.search(r"\bbumper(s)?\b", joined):
        return "bumper"
    if re.search(r"\b(station ids?|idents?|ident|ids?)\b", joined):
        return "station_id"
    if re.search(r"\b(network promos?|promos?)\b", joined):
        return "promo"
    return "commercial"


def infer_commercial_era_from_parts(parts):
    for part in parts:
        era = normalize_commercial_era(part)
        if era:
            return era
    return ""


def infer_program_era_from_path(path, channel_name=""):
    haystack = " ".join(
        part for part in (
            channel_name,
            os.path.basename(os.path.dirname(path or "")),
            os.path.basename(path or ""),
        )
        if part
    )
    lower = haystack.lower()
    if re.search(r"\b(80s|198[0-9])\b", lower):
        return "80s"
    if re.search(r"\b(90s|199[0-9])\b", lower):
        return "90s"
    if re.search(r"\b(2000s|200[0-9]|00s)\b", lower):
        return "2000s"
    if re.search(r"\b(2010s|201[0-9])\b", lower):
        return "2010s"
    if re.search(r"\b(70s|197[0-9])\b", lower):
        return "70s"
    return ""


def infer_program_category_from_path(path, channel_name=""):
    haystack = " ".join(
        part for part in (
            channel_name,
            os.path.dirname(path or ""),
            os.path.basename(path or ""),
        )
        if part
    ).lower()
    category_rules = (
        ("kids", ("kids", "cartoon", "nick", "toon", "4kids", "family", "disney")),
        ("toys", ("toy", "toys")),
        ("food", ("food", "fast food", "restaurant")),
        ("tech", ("tech", "computer", "electronics")),
        ("games", ("game", "gaming", "video game")),
        ("music", ("music", "mtv", "vh1")),
        ("sports", ("sports", "espn", "nascar", "football", "baseball", "basketball")),
        ("movies", ("movie", "cinema", "theater")),
    )
    for label, tokens in category_rules:
        if any(token in haystack for token in tokens):
            return label
    return ""


def build_commercial_root_signature(root_folder):
    root = os.path.abspath(os.path.expanduser(root_folder or ""))
    if not root or not os.path.isdir(root):
        return ""
    files = []
    for walk_root, dirnames, filenames in os.walk(root):
        dirnames.sort(key=str.casefold)
        for file_name in sorted(filenames, key=str.casefold):
            if not file_name.lower().endswith(VIDEO_EXTS):
                continue
            full_path = os.path.join(walk_root, file_name)
            try:
                stat = os.stat(full_path)
            except OSError:
                continue
            files.append(
                {
                    "path": os.path.relpath(full_path, root),
                    "mtime": int(stat.st_mtime),
                    "size": int(stat.st_size),
                }
            )
    return stable_hash(json.dumps({"root": root, "files": files}, sort_keys=True))


def density_ad_range(profile):
    density = str((profile or {}).get("density", "light") or "light").lower()
    if density == "custom":
        minimum = max(0, int((profile or {}).get("min_ads_per_break", 1) or 0))
        maximum = max(minimum, int((profile or {}).get("max_ads_per_break", minimum) or minimum))
        return minimum, maximum
    return COMMERCIAL_DENSITY_PRESETS.get(density, COMMERCIAL_DENSITY_PRESETS["light"])


def commercial_profile_signature(profile):
    return stable_hash(json.dumps(profile or {}, sort_keys=True))


def schedule_entry_user_title(entry, fallback_title="", fallback_path=""):
    entry = entry or {}
    if entry.get("is_commercial") or entry.get("kind") in {"commercial", "promo", "bumper", "station_id"}:
        return entry.get("parent_title") or entry.get("slot_title") or fallback_title or format_program_title(entry.get("parent_path") or fallback_path)
    return entry.get("display_title") or entry.get("title") or fallback_title or format_program_title(entry.get("path") or fallback_path)


def schedule_entry_user_summary(entry, fallback_summary=""):
    entry = entry or {}
    if entry.get("is_commercial") or entry.get("kind") in {"commercial", "promo", "bumper", "station_id"}:
        return entry.get("parent_summary") or fallback_summary
    return entry.get("summary") or fallback_summary


def schedule_entry_user_path(entry, fallback_path=""):
    entry = entry or {}
    if entry.get("is_commercial") or entry.get("kind") in {"commercial", "promo", "bumper", "station_id"}:
        return entry.get("parent_path") or fallback_path or entry.get("path", "")
    return entry.get("path", "") or fallback_path


